ALTER SESSION SET CONTAINER = XEPDB1;
ALTER SESSION SET CURRENT_SCHEMA = RM565468;

DROP TABLE "EVENTO_CUIDADO" CASCADE CONSTRAINTS;
DROP TABLE "PET" CASCADE CONSTRAINTS;
DROP TABLE "TUTOR" CASCADE CONSTRAINTS;

CREATE TABLE "TUTOR" (
    "ID_TUTOR"  NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY,
    "NOME"      NVARCHAR2(100) NOT NULL,
    "EMAIL"     NVARCHAR2(100) NULL,
    "TELEFONE"  NVARCHAR2(20)  NULL,
    CONSTRAINT "PK_TUTOR" PRIMARY KEY ("ID_TUTOR")
);

CREATE TABLE "PET" (
    "ID_PET"    NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY,
    "NOME"      NVARCHAR2(100) NOT NULL,
    "ESPECIE"   NVARCHAR2(50)  NULL,
    "RACA"      NVARCHAR2(50)  NULL,
    "IDADE"     NUMBER(10)     NULL,
    "ID_TUTOR"  NUMBER(10)     NOT NULL,
    CONSTRAINT "PK_PET" PRIMARY KEY ("ID_PET"),
    CONSTRAINT "FK_PET_TUTOR_ID_TUTOR" FOREIGN KEY ("ID_TUTOR")
        REFERENCES "TUTOR" ("ID_TUTOR") ON DELETE CASCADE
);

CREATE INDEX "IX_PET_ID_TUTOR" ON "PET" ("ID_TUTOR");

CREATE TABLE "EVENTO_CUIDADO" (
    "ID_EVENTO"     NUMBER(10) GENERATED BY DEFAULT ON NULL AS IDENTITY,
    "ID_PET"        NUMBER(10)      NOT NULL,
    "TIPO_CUIDADO"  NVARCHAR2(50)   NOT NULL,
    "DATA_PREVISTA" TIMESTAMP(7)    NULL,
    "STATUS"        NVARCHAR2(30)   NOT NULL,
    "PRIORIDADE"    NVARCHAR2(20)   NULL,
    "OBSERVACAO"    NVARCHAR2(500)  NULL,
    CONSTRAINT "PK_EVENTO_CUIDADO" PRIMARY KEY ("ID_EVENTO"),
    CONSTRAINT "FK_EVENTO_CUIDADO_PET_ID_PET" FOREIGN KEY ("ID_PET")
        REFERENCES "PET" ("ID_PET") ON DELETE CASCADE,
    CONSTRAINT "CK_EVENTO_CUIDADO_STATUS" CHECK ("STATUS" IN ('PENDENTE', 'REALIZADO', 'CANCELADO'))
);

CREATE INDEX "IX_EVENTO_CUIDADO_ID_PET" ON "EVENTO_CUIDADO" ("ID_PET");
